class Node:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

def insert_char(char, root):
    if char < root.value:
        if root.left is None:
            root.left = Node(char)
        else:
            insert_char(char, root.left)
    elif char > root.value:
        if root.right is None:
            root.right = Node(char)
        else:
            insert_char(char, root.right)

def process_sequence(sequence):
    root = None
    for char in sequence:
        insert_char(char.lower(), root)
    return root

